import React from 'react';
import { BrowserRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import ProductsPage from './pages/ProductsPage';
import AdminPage from './pages/AdminPage';

const ProtectedRoute = ({ children, requiredRole }) => {
  const { isAuthenticated, user, isAdmin, isSeller } = useAuth();

  if (!isAuthenticated) {
    return <Navigate to="/login" />;
  }

  if (requiredRole === 'admin' && !isAdmin) {
    return <Navigate to="/" />;
  }

  if (requiredRole === 'seller' && !isSeller) {
    return <Navigate to="/" />;
  }

  return children;
};

function NavBar() {
  const { isAuthenticated, user, logout } = useAuth();

  return (
    <nav style={styles.nav}>
      <div style={styles.navContainer}>
        <Link to="/" style={styles.logo}>🛒 Shop</Link>
        <div style={styles.links}>
          <Link to="/" style={styles.link}>Главная</Link>
          <Link to="/products" style={styles.link}>Товары</Link>
          {user?.role === 'admin' && (
            <Link to="/admin" style={styles.link}>Админка</Link>
          )}
          {isAuthenticated ? (
            <>
              <span style={styles.user}>
                {user?.first_name} ({user?.role})
              </span>
              <button onClick={logout} style={styles.logoutBtn}>Выйти</button>
            </>
          ) : (
            <>
              <Link to="/login" style={styles.link}>Вход</Link>
              <Link to="/register" style={styles.link}>Регистрация</Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}

function AppContent() {
  return (
    <>
      <NavBar />
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/login" element={<LoginPage />} />
        <Route path="/register" element={<RegisterPage />} />
        <Route path="/products" element={
          <ProtectedRoute>
            <ProductsPage />
          </ProtectedRoute>
        } />
        <Route path="/admin" element={
          <ProtectedRoute requiredRole="admin">
            <AdminPage />
          </ProtectedRoute>
        } />
      </Routes>
    </>
  );
}

function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <AppContent />
      </AuthProvider>
    </BrowserRouter>
  );
}

// ========== УЛУЧШЕННЫЕ КОНТРАСТНЫЕ СТИЛИ ==========
const styles = {
  nav: { 
    background: '#0a0c14', 
    padding: '15px 0', 
    borderBottom: '2px solid #4ade80',
    boxShadow: '0 2px 10px rgba(0,0,0,0.5)'
  },
  navContainer: { 
    maxWidth: '1200px', 
    margin: '0 auto', 
    display: 'flex', 
    justifyContent: 'space-between', 
    alignItems: 'center', 
    padding: '0 20px' 
  },
  logo: { 
    color: '#4ade80', 
    fontSize: '24px', 
    fontWeight: 'bold', 
    textDecoration: 'none',
    textShadow: '0 0 5px rgba(74, 222, 128, 0.5)'
  },
  links: { 
    display: 'flex', 
    gap: '25px', 
    alignItems: 'center' 
  },
  link: { 
    color: '#ffffff', 
    textDecoration: 'none',
    fontSize: '16px',
    fontWeight: '500',
    transition: 'color 0.2s',
    ':hover': { color: '#4ade80' }
  },
  user: { 
    color: '#4ade80', 
    marginRight: '15px',
    fontWeight: 'bold',
    background: 'rgba(74, 222, 128, 0.15)',
    padding: '5px 10px',
    borderRadius: '20px'
  },
  logoutBtn: { 
    background: '#ff4444', 
    color: 'white', 
    border: 'none', 
    padding: '6px 15px', 
    borderRadius: '6px', 
    cursor: 'pointer',
    fontWeight: 'bold',
    transition: 'background 0.2s',
    ':hover': { background: '#cc0000' }
  }
};

export default App;
